    alpha = 0.1
    for group, sub in counts.groupby('group'):
        sub = sub.sort_values('year')
        years = list(range(sub['year'].min(), sub['year'].max()+1))
        year_to_count = {int(r.year): int(r['count']) for r in sub.itertuples(index=False)}
